xtContent = accountInput.value || '110-123-456789';\n        document.getElementById('cardHolderName').textContent = holderInput.value || '\xEA\xB9\x80\xEC\x9D\xBC\xEC\x9E\x98';\n\n        cardEl.style.background = `linear-gradient(135deg, ${colors[0]}, ${colors[1]})`;\n        cardEl.style.color = colors[2];\n        document.getElementById('cardAccountNumber').style.textShadow = colors[3];\n      }\n\n      if(nameInput) {\n        nameInput.addEventListener('change', updateCard);\n        accountInput.addEventListener('input', updateCard);\n        holderInput.addEventListener('input', updateCard);\n        updateCard(); // \xEC\xB4\x88\xEA\xB8\xB0\xED\x99\x94\n      }\n    });\n\n    async function generateAndShareBankCard() {\n      const btn = document.getElementById('shareBankCardBtn');\n      const status = document.getElementById('cardShareStatus');\n      const cardEl = document.getElementById('bankCardElement');\n      const bankName = document.getElementById('bankNameInput').value;\n      const bankAcc = document.getElementById('bankAccountInput').value;\n      const bankHolder = document.getElementById('bankHolderInput').value;\n\n      if (!bankName || !bankAcc) {\n        alert(\"\xEC\x9D\x80\xED\x96\x89\xEB\xAA\x85\xEA\xB3\xBC \xEA\xB3\x84\xEC\xA2\x8C\xEB\xB2\x88\xED\x98\xB8\xEB\xA5\xBC \xEB\xA8\xBC\xEC\xA0\x80 \xEC\x9E\x85\xEB\xA0\xA5\xED\x95\xB4\xEC\xA3\xBC\xEC\x84\xB8\xEC\x9A\x94.\");\n        if(!bankName) document.getElementById('bankNameInput').focus();\n        else document.getElementById('bankAccountInput').focus();\n        return;\n      }\n\n      // \xEA\xB3\xB5\xEC\x9C\xA0 \xEC\xA0\x84 \xED\x8F\xBC \xEC\x9E\x90\xEB\x8F\x99 \xEC\xA0\x80\xEC\x9E\xA5 \xED\x8A\xB8\xEB\xA6\xAC\xEA\xB1\xB0\n      const updateForm = btn.closest('form');\n      if (updateForm) {\n        const formData = new FormData(updateForm);\n        fetch(updateForm.action, {\n          method: updateForm.method.toUpperCase(),\n          body: formData,\n          headers