teBizCard);\n        updateBizCard();\n      }\n    });\n\n    async function generateAndShareBizCard() {\n      const btn = document.getElementById('shareBizCardBtn');\n      const status = document.getElementById('bcShareStatus');\n      const cardEl = document.getElementById('bcTemplate' + currentBcTemplate);\n      \n      const tName = document.getElementById('bcNameInput').value;\n      const tRole = document.getElementById('bcRoleInput').value;\n      const tPhone = document.getElementById('bcPhoneInput').value;\n\n      btn.disabled = true;\n      const originalText = btn.innerHTML;\n      btn.innerHTML = '\xE2\x8F\xB3 \xEB\xAA\x85\xED\x95\xA8 \xEC\xA0\x9C\xEC\x9E\x91\xEC\x86\x8C \xEC\x9E\x90\xEB\x8F\x99 \xEC\xB6\x9C\xEB\xA0\xA5 \xEC\xA4\x91...';\n      btn.style.transform = 'scale(0.98)';\n\n      try {\n        const canvas = await html2canvas(cardEl, {\n          scale: 4, \n          backgroundColor: currentBcTemplate === 'A' ? '#111827' : '#ffffff',\n          logging: false\n        });\n\n        canvas.toBlob(async function(blob) {\n          const file = new File([blob], 'biz_card.png', { type: 'image/png' });\n          const textMsg = `[\xED\x98\x84\xEC\x9E\xA5 \xEC\xA0\x84\xEB\xAC\xB8\xEA\xB0\x80 \xEB\xAA\x85\xED\x95\xA8]\\n\xEC\x9D\xB4\xEB\xA6\x84: ${tName}\\n\xEC\xA7\x81\xED\x95\xA8: ${tRole}\\n\xEC\xA0\x84\xED\x99\x94: ${tPhone}`;\n\n          if (navigator.canShare && navigator.canShare({ files: [file] })) {\n            await navigator.share({\n              title: '\xEB\xAA\xA8\xEB\xB0\x94\xEC\x9D\xBC \xEB\xAA\x85\xED\x95\xA8',\n              text: textMsg,\n              files: [file]\n            });\n            showSuccess();\n          } else if (navigator.share) {\n            await navigator.share({\n              title: '\xEB\xAA\xA8\xEB\xB0\x94\xEC\x9D\xBC \xEB\xAA\x85\xED\x95\xA8',\n              text: textMsg\n            });\n            showSuccess();\n          } else {\n             navigator.clipboard.writeText(textMsg);\n             const url = URL.createObjectURL(blob);\n             const a = document.createElement('a');\n             a.href = url;\n             a.download = 'biz_card.png';\n             a.click();\n             alert(\"\xEB\xAA\x85\xED\x95\xA8 \xEC\xA0\x95\xEB\xB3\xB4\xEA\xB0\x80 \xEB\xB3\xB5\xEC\x82\xAC\xEB\x90\x98\xEC\x97\x88\xEA\xB3\xA0 \xEC\x9D\xB4\xEB\xAF\xB8\xEC\xA7\x80\xEA\xB0\x80 \xEB\x8B\xA4\xEC\x9A\xB4\xEB\xA1\x9C\xEB\x93\x9C \xEB\x90\x98\xEC\x97\x88\xEC\x8A\xB5\xEB\x8B\x88\xEB\x8B\xA4.\");\n             showSuccess();\n          }\n        }, 'image/png', 1.0);\n      } catch (e) {\n        alert(\"\xEC\x9D\xBC\xEC\x8B\x9C\xEC\xA0\x81\xEC\x9D\xB8 \xEC\x98\xA4\xEB\xA5\x98\xEB\xA1\x9C \xEC\x9D\xB4\xEB\xAF\xB8\xEC\xA7\x80\xEB\xA5\xBC \xEC\x83\x9D\xEC\x84\xB1\xED\x95\x98\xEC\xA7\x80 \xEB\xAA\xBB\xED\x96\x88\xEC\x8A\xB5\xEB\x8B\x88\xEB\x8B\xA4.\");\n      } finally {\n        setTimeout(() => {\n          btn.disabled = false;\n          btn.innerHTML = originalText;\n          btn.style.transform = 'scale(1)';\n        }, 800);\n      }\n      \n      function showSuccess() {\n        status.style.display = 'block';\n        setTimeout(() => { status.style.display = 'none'; }, 5000);\n      }\n    }\n\n    async function showImageForDownload(cardEl, bgColor) {\n      document.getElementById('imageDownloadModal').style.display = 'flex';\n      document.getElementById('downloadedImagePreview').src = '';\n      try {\n        const canvas = await html2canvas(cardEl, { scale: 4, backgroundColor: bgColor, logging: false });\n        const imgData = canvas.toDataURL('image/png');\n        document.getElementById('downloadedImagePreview').src = imgData;\n      } catch(e) {\n        alert(\"\xEC\x9D\xBC\xEC\x8B\x9C\xEC\xA0\x81\xEC\x9D\xB8 \xEC\x98\xA4\xEB\xA5\x98\xEB\xA1\x9C \xEC\xA0\x80\xEC\x9E\xA5 \xED\x8C\x9D\xEC\x97\x85\xEC\x9D\x84 \xEC\x97\xB4\xEC\xA7\x80 \xEB\xAA\xBB\xED\x96\x88\xEC\x8A\xB5\xEB\x8B\x88\xEB\x8B\xA4.\");\n        document.getElementById('imageD